Here's a complete implementation:

### XAML

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemListPage"
             x:DataType="vm:ItemListViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}"
                        EmptyView="No items found.">
            <CollectionView.ItemsLayout>
                <LinearItemsLayout Orientation="Vertical"
                                   ItemSizingStrategy="MeasureFirstItem" />
            </CollectionView.ItemsLayout>
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}"
                                   FontSize="12" TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

### ViewModel

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemListViewModel : ObservableObject
{
    private readonly IItemService _itemService;

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _currentItem;

    public ItemListViewModel(IItemService itemService)
    {
        _itemService = itemService;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _itemService.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false;   // must set false to hide spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync($"detail?id={CurrentItem.Id}");

        CurrentItem = null;   // reset so the same item can be re-selected
    }
}
```

### Key binding relationships

| XAML property | ViewModel property | Purpose |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool, TwoWay) | Shows/hides spinner; **you** set it `false` when done |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-to-refresh |
| `SelectedItem` | `CurrentItem` (TwoWay) | Tracks selected item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap → navigates |
| `ItemsSource` | `Items` (`ObservableCollection<T>`) | Auto-updates UI on add/remove |

### Important details

- **`ObservableCollection<T>`** — not `List<T>` — so the UI reacts to changes.
- **`IsRefreshing = false`** in a `finally` block so the spinner always dismisses.
- **`CurrentItem = null`** after navigation lets the user re-select the same item.
- **`MeasureFirstItem`** improves scroll performance for uniform-height rows.
- **`x:DataType`** on both the page and the `DataTemplate` enables compiled bindings.
- Register the detail route in `AppShell.xaml.cs`: `Routing.RegisterRoute("detail", typeof(DetailPage));`
